import React, { useState, useEffect } from 'react';
import './WaitingScreen.css';

const INITIAL_SECONDS = 8 * 60;

const DRIVER_INFO = {
  vehicle: '경북 72가 3847',
  model: '기아 카니발 (흰색)',
  driver: '김영주',
  phone: '010-5892-****',
};

export default function WaitingScreen({ bookingInfo, onBack }) {
  const [seconds, setSeconds] = useState(INITIAL_SECONDS);
  const [arrived, setArrived] = useState(false);

  useEffect(() => {
    if (seconds <= 0) {
      setArrived(true);
      return;
    }
    const id = setInterval(() => {
      setSeconds((s) => s - 1);
    }, 1000);
    return () => clearInterval(id);
  }, [seconds]);

  const mins = String(Math.floor(seconds / 60)).padStart(2, '0');
  const secs = String(seconds % 60).padStart(2, '0');
  const progress = 1 - seconds / INITIAL_SECONDS;

  const circumference = 2 * Math.PI * 52;

  return (
    <div className="waiting-screen">
      {/* 상태 헤더 */}
      <div className={`waiting-header ${arrived ? 'arrived' : ''}`}>
        <button className="back-btn-w" onClick={onBack}>‹</button>
        <div className="status-badge">
          {arrived ? '✅ 차량 도착' : '🚌 차량 이동 중'}
        </div>
      </div>

      {/* 여정 정보 */}
      <div className="trip-summary">
        <span className="trip-from">{bookingInfo.departure}</span>
        <span className="trip-arrow">→</span>
        <span className="trip-to">{bookingInfo.destination.name}</span>
        <span className="trip-time-badge">{bookingInfo.time}</span>
      </div>

      {/* 타이머 */}
      <div className="timer-wrap">
        <div className="timer-circle-outer">
          <svg width="140" height="140" viewBox="0 0 140 140">
            <circle
              cx="70" cy="70" r="52"
              fill="none"
              stroke="#e0f5f0"
              strokeWidth="10"
            />
            <circle
              cx="70" cy="70" r="52"
              fill="none"
              stroke={arrived ? '#A4CF4A' : '#35C8B4'}
              strokeWidth="10"
              strokeLinecap="round"
              strokeDasharray={circumference}
              strokeDashoffset={circumference * (1 - progress)}
              transform="rotate(-90 70 70)"
              style={{ transition: 'stroke-dashoffset 0.9s linear, stroke 0.4s' }}
            />
          </svg>
          <div className="timer-inner">
            {arrived ? (
              <span className="timer-arrived">탑승!</span>
            ) : (
              <>
                <span className="timer-digits">{mins}:{secs}</span>
                <span className="timer-label">남은 시간</span>
              </>
            )}
          </div>
        </div>
        <p className="timer-desc">
          {arrived
            ? '차량이 도착했습니다. 탑승해 주세요!'
            : '차량이 곧 도착합니다. 승차 위치에서 대기해 주세요.'}
        </p>
      </div>

      {/* 차량/기사 정보 */}
      <div className="vehicle-card">
        <p className="vehicle-card-title">차량 정보</p>
        <div className="vehicle-rows">
          <div className="vehicle-row">
            <span className="v-icon">🚗</span>
            <div>
              <p className="v-main">{DRIVER_INFO.vehicle}</p>
              <p className="v-sub">{DRIVER_INFO.model}</p>
            </div>
          </div>
          <div className="vehicle-divider" />
          <div className="vehicle-row">
            <span className="v-icon">👤</span>
            <div>
              <p className="v-main">{DRIVER_INFO.driver} 기사님</p>
              <p className="v-sub">{DRIVER_INFO.phone}</p>
            </div>
          </div>
        </div>
      </div>

      {/* 예약 요약 */}
      <div className="booking-summary">
        <div className="summary-row">
          <span>탑승 인원</span>
          <span>{bookingInfo.passengers}명</span>
        </div>
        <div className="summary-row">
          <span>결제 요금</span>
          <span className="summary-fare">{bookingInfo.total.toLocaleString()}원</span>
        </div>
      </div>

      {/* 취소 버튼 */}
      <div className="cancel-wrap">
        <button className="cancel-btn" onClick={onBack}>예약 취소</button>
      </div>
    </div>
  );
}
